def compute_score() -> tuple[str, float]:
    """Scores whether a callout shape on slide 5 has no fill.

    Notes:
    - Avoids mutating the presentation (no calls like fill.solid()).
    - Handles python-pptx enums safely (no .lower() on enum objects).
    - Detects callouts by name or MSO auto-shape type containing 'CALLOUT'.
    """
    from pptx import Presentation

    def is_callout(shape) -> bool:
        # Heuristic 1: shape name contains 'callout'
        name = getattr(shape, "name", "") or ""
        if isinstance(name, str) and "callout" in name.lower():
            return True
        # Heuristic 2: auto shape type name contains 'CALLOUT'
        try:
            st = getattr(shape, "shape_type", None)
            st_name = getattr(st, "name", "")  # Enum has .name; fallback to empty string
            if st_name == "AUTO_SHAPE":
                auto = getattr(shape, "auto_shape_type", None)
                auto_name = getattr(auto, "name", str(auto))
                if isinstance(auto_name, str) and "CALLOUT" in auto_name:
                    return True
        except Exception:
            pass
        return False

    def has_no_fill(shape) -> bool:
        try:
            fill = getattr(shape, "fill", None)
            if not fill:
                # No fill interface available, cannot determine - assume it has fill to be conservative
                return False

            ftype = getattr(fill, "type", None)
            if ftype is None:
                # Cannot determine fill type, assume it has fill to be conservative
                return False

            # Get the fill type name safely
            ftype_name = getattr(ftype, "name", str(ftype))

            # Only consider explicit NO_FILL types as having no fill
            if isinstance(ftype_name, str):
                # Check for explicit no fill types
                if "NO_FILL" in ftype_name.upper():
                    return True
                # BACKGROUND fill type might also indicate no visible fill
                if "BACKGROUND" in ftype_name.upper():
                    return True

            # For any other fill type (SOLID, GRADIENT, PATTERN, etc.), consider it as having fill
            return False

        except Exception:
            # If any exception occurs, assume the shape has fill to be conservative
            return False

    prs = Presentation(modified_ppt_path)
    slide = prs.slides[4]
    for shape in slide.shapes:
        if is_callout(shape):
            if has_no_fill(shape):
                return "Callout shape found with no fill.", 1.0
            return "Callout shape has a fill.", 0.0
    return "No callout shape found to check fill property.", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    def get_name(shape) -> str:
        name = getattr(shape, "name", "")
        return name or ""

    def is_callout(shape) -> bool:
        # Heuristic 1: name contains 'callout'
        if "callout" in get_name(shape).lower():
            return True
        # Heuristic 2: auto shape type enum includes 'CALLOUT'
        try:
            st = getattr(shape, "shape_type", None)
            if getattr(st, "name", None) == "AUTO_SHAPE":
                auto = getattr(shape, "auto_shape_type", None)
                auto_name = getattr(auto, "name", str(auto))
                if isinstance(auto_name, str) and "CALLOUT" in auto_name:
                    return True
        except Exception:
            pass
        return False

    prs = Presentation(modified_ppt_path)
    slide = prs.slides[4]

    callout_count = sum(1 for shape in slide.shapes if is_callout(shape))
    if callout_count > 1:
        return f"{callout_count} callout shapes found (expected 1).", 0.0

    # Check for new shapes that are not the callout
    orig_prs = Presentation(original_ppt_path)
    orig_shapes = [get_name(shape) for shape in orig_prs.slides[4].shapes]
    new_shapes = [get_name(shape) for shape in slide.shapes]
    extraneous = [sh for sh in new_shapes if sh not in orig_shapes and "callout" not in (sh or "").lower()]
    if extraneous:
        return f"Extraneous non-callout shapes added: {extraneous}", 0.0
    return "No extraneous or duplicate shapes added.", 1.0
